headers = {
    "apikey": KEY,
    "Authorization": f"Bearer {KEY}",
    "Content-Type": "application/json",
    "Prefer": "return=minimal"
}

ok = fail = 0
for name_ru, (desc_kk, desc_ru) in DESCS.items():
    encoded = urllib.parse.quote(name_ru)
    patch_url = f"{URL}/rest/v1/menu_items?name_ru=eq.{encoded}&cafe_id=eq.{CAFE}"
    data = json.dumps({"description_kk": desc_kk, "description_ru": desc_ru, "description_en": desc_ru}).encode()
    req = urllib.request.Request(patch_url, data=data, headers=headers, method="PATCH")
    try:
        with urllib.request.urlopen(req) as r:
            ok += 1
            print(f"✅ {name_ru}")
    except Exception as e:
        fail += 1
        print(f"❌ {name_ru}: {e}")

print(f"\n✅ Жаңартылды: {ok} | ❌ Қате: {fail}")

